import React from 'react';
import styles from './Statistic.module.css';

export interface StatisticProps {
  title?: React.ReactNode;
  value?: number | string;
  formatter?: (value: number | string) => React.ReactNode;
  suffix?: React.ReactNode;
  valueStyle?: React.CSSProperties;
  className?: string;
}

const Statistic: React.FC<StatisticProps> = ({ title, value, formatter, suffix, valueStyle, className }) => {
  return (
    <div className={`${styles.statistic} ${className || ''}`}>
      {title && <div className={styles.title}>{title}</div>}
      <div className={styles.value} style={valueStyle}>
        {formatter && value !== undefined ? formatter(value) : value ?? '-'}
        {suffix && <span className={styles.suffix}>{suffix}</span>}
      </div>
    </div>
  );
};

export default Statistic;
