import React from 'react';
import styles from './AlertBanner.module.css';

type AlertType = 'error' | 'warning' | 'info' | 'success';

interface AlertBannerProps {
  type: AlertType;
  message: string;
}

const typeClass: Record<AlertType, string> = {
  error: styles.error,
  warning: styles.warning,
  info: styles.info,
  success: styles.success,
};

const typeIcons: Record<AlertType, string> = {
  error: 'fas fa-times-circle',
  warning: 'fas fa-exclamation-triangle',
  info: 'fas fa-info-circle',
  success: 'fas fa-check-circle',
};

const AlertBanner: React.FC<AlertBannerProps> = ({ type, message }) => (
  <div className={`${styles.banner} ${typeClass[type]}`}>
    <i className={typeIcons[type]} style={{ marginRight: 8 }} />
    {message}
  </div>
);

export default AlertBanner;
