import React, { useState } from 'react';
import { Button } from '@linm-soft-org/linm-web-common-components';
import styles from './Popconfirm.module.css';

export interface PopconfirmProps {
  title: string;
  onConfirm: () => void;
  children: React.ReactElement;
}

const Popconfirm: React.FC<PopconfirmProps> = ({ title, onConfirm, children }) => {
  const [open, setOpen] = useState(false);

  const handleClick = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setOpen(true);
  };

  return (
    <span className={styles.wrapper}>
      <span onClick={handleClick}>{children}</span>
      {open && (
        <span className={styles.popup}>
          <span className={styles.arrow} />
          <span className={styles.message}>{title}</span>
          <span className={styles.actions}>
            <Button variant="secondary" size="sm" onClick={() => setOpen(false)}>
              Hủy
            </Button>
            <Button
              variant="primary"
              size="sm"
              onClick={() => { setOpen(false); onConfirm(); }}
            >
              Đồng ý
            </Button>
          </span>
        </span>
      )}
    </span>
  );
};

export default Popconfirm;
