import React from 'react';
import styles from './Typography.module.css';

interface TitleProps {
  level?: 1 | 2 | 3 | 4 | 5;
  children: React.ReactNode;
  style?: React.CSSProperties;
  className?: string;
}

export const Title: React.FC<TitleProps> = ({ level = 3, children, style, className }) => {
  const Tag = `h${level}` as keyof JSX.IntrinsicElements;
  const cls = [styles.title, styles[`h${level}`], className].filter(Boolean).join(' ');
  return <Tag className={cls} style={style}>{children}</Tag>;
};

interface TextProps {
  type?: 'success' | 'danger' | 'warning' | 'secondary';
  strong?: boolean;
  children: React.ReactNode;
  style?: React.CSSProperties;
}

export const Text: React.FC<TextProps> = ({ type, strong, children, style }) => {
  const colorMap: Record<string, string> = {
    success: '#3f8600',
    danger: '#cf1322',
    warning: '#faad14',
    secondary: '#8c8c8c',
  };
  return (
    <span
      style={{
        fontWeight: strong ? 600 : undefined,
        color: type ? colorMap[type] : undefined,
        ...style,
      }}
    >
      {children}
    </span>
  );
};
